Here are the authoritative public test cases for feature3_error_detail_unpacking:
{
  "description": "An RPC error that carries repeated typed detail payloads must expose every detail that can be unpacked by the supplied detail parser while preserving the RPC error code.",
  "cases": [
    {
      "input": "type|value|unpacked_value|2",
      "expected_output": "code=unknown\nunpacked=unpacked_value,unpacked_value\n"
    }
  ]
}

Here are the authoritative public test cases for feature2_5_stream_header_result_order:
{
  "description": "For streaming response headers, inbound result filters must be applied in reverse registration order after protocol content-type validation succeeds.",
  "cases": [
    {
      "input": "1,2,3,4",
      "expected_output": "headers.id=4,3,2,1\n"
    }
  ]
}

Here are the authoritative public test cases for feature2_4_stream_request_body_order:
{
  "description": "For a streaming request body, outbound body filters must be applied in registration order before the protocol framing layer emits the body as a single message envelope.",
  "cases": [
    {
      "input": "1,2,3,4",
      "expected_output": "envelope.header=0\nbody=1234\n"
    }
  ]
}

Here are the authoritative public test cases for feature2_3_stream_request_order:
{
  "description": "For a streaming request, outbound request filters must be applied in registration order and expose the accumulated header mutations on the resulting request.",
  "cases": [
    {
      "input": "1,2,3,4",
      "expected_output": "headers.id=1,2,3,4\n"
    }
  ]
}

Here are the authoritative public test cases for feature2_2_unary_response_order:
{
  "description": "For a unary response, inbound response filters must be applied in reverse registration order so the last registered filter observes the response first.",
  "cases": [
    {
      "input": "1,2,3,4",
      "expected_output": "headers.id=4,3,2,1\n"
    }
  ]
}

Here are the authoritative public test cases for feature2_1_unary_interceptor_order:
{
  "description": "For a unary request, outbound request filters must be applied in the same order in which they were registered, with each filter able to append observable header state.",
  "cases": [
    {
      "input": "1,2,3,4",
      "expected_output": "headers.id=1,2,3,4\n"
    }
  ]
}

Here are the authoritative public test cases for feature1_2_host_url_scheme_validation:
{
  "description": "A client configuration must reject endpoint URLs whose scheme is not a supported HTTP transport scheme and report a normalized argument error.",
  "cases": [
    {
      "input": "xhtp://service.example",
      "expected_output": "error=invalid_argument\n"
    }
  ]
}

Here are the authoritative public test cases for feature1_1_host_url_parsing:
{
  "description": "A client configuration created from an HTTP endpoint must expose the endpoint host and preserve an optional path prefix for later request routing.",
  "cases": [
    {
      "input": "https://service.example",
      "expected_output": "scheme=https\nhost=service.example\npath=\n"
    },
    {
      "input": "https://service.example/api/v1",
      "expected_output": "scheme=https\nhost=service.example\npath=/api/v1\n"
    }
  ]
}
